        void SetFontHinting(int size, Font::Hinting hinting);
        int GetFontOutline(int size);
        void SetFontOutline(int size, int outline);
        Point GetTextSize(int fontSize, const std::string& text);
        int CountTextFit(int fontSize, const std::string& text, int measureWidth);
        int WidthTextFit(int fontSize, const std::string& text, int measureWidth);

    private:
        void ClearFonts();
        void MeasureText(int fontSize, const std::string& text, int measureWidth, int& count, int& width);

        std::string filePath;
        std::unordered_map<int, TTF_Font*> fontSizes;
